 1	import * as React from 'react';
 2	import { Thead, Tbody, Th, Td, Tr } from '@patternfly/react-table';
 3	import { Table } from '@patternfly/react-table';
 4	import { useTranslation } from 'react-i18next';
 5	import { TektonResultsRun } from '../../types';
 6	import { SectionHeading } from '../pipelines-tasks/tasks-details-pages/headings';
 7	import { handleURLs } from '../utils/render-utils';
 8	
 9	export interface ResultsListProps {
10	  results: TektonResultsRun[];
11	  resourceName: string;
12	}
13	
14	const ResultsList: React.FC<ResultsListProps> = ({ results, resourceName }) => {
15	  const { t } = useTranslation('plugin__pipelines-console-plugin');
16	  if (!results.length) return null;
17	
18	  return (
19	    <>
20	      <SectionHeading text={t('{{resourceName}} results', { resourceName })} />
21	      <Table
22	        aria-label={t('{{resourceName}} results', {
23	          resourceName,
24	        })}
25	        data-codemods="true"
26	      >
27	        <Thead>
28	          <Tr>
29	            <Th>{t('Name')}</Th>
30	            <Th>{t('Value')}</Th>
31	          </Tr>
32	        </Thead>
33	        <Tbody>
34	          {results.map(({ name, value }) => (
35	            <Tr key={`row-${name}`}>
36	              <Td>{name}</Td>
37	              <Td>{handleURLs(value)}</Td>
38	            </Tr>
39	          ))}
40	        </Tbody>
41	      </Table>
42	    </>
43	  );
44	};
45	
46	export default ResultsList;

